public List fullJustify(String[] words, int maxWidth) {
    List result = new ArrayList<>();
    int i = 0;

    while (i < words.length) {
        int j = i;
        int lineLength = 0;

        while (j < words.length && lineLength + words[j].length() + (j - i) <= maxWidth) {
            lineLength += words[j].length();
            j++;
        }

        StringBuilder line = new StringBuilder();
        int spaces = maxWidth - lineLength;

        if (j == words.length || j - i == 1) {
            // Left justify
            for (int k = i; k < j; k++) {
                line.append(words[k]);
                if (k < j - 1) line.append(" ");
            }
            while (line.length() < maxWidth) {
                line.append(" ");
            }
        } else {
            // Full justify
            int gaps = j - i - 1;
            int spacesPerGap = gaps == 0 ? 0 : spaces / gaps;
            int extraSpaces = gaps == 0 ? 0 : spaces % gaps;

            for (int k = i; k < j; k++) {
                line.append(words[k]);
                if (k < j - 1) {
                    int spacesToAdd = spacesPerGap + (extraSpaces-- > 0 ? 1 : 0);
                    for (int s = 0; s < spacesToAdd; s++) {
                        line.append(" ");
                    }
                }
            }
        }

        result.add(line.toString());
        i = j;
    }

    return result;
}
